arguments.argument:
if global.gamePaused=false
{
  chainProg+=1
  if chainProg>=1 and chainProg<=16
  {
    image_xscale+=(0.5*ownerID.image_xscale)
  }
  else if chainProg>=19 and chainProg<=34
  {
    image_xscale-=(0.5*ownerID.image_xscale)
  }
  else if chainProg>=35
  {
    ownerID.attackDelay=200
    instance_destroy()
  }
}
